!function(){
  if(window.__CBT_ADMIN_SIGNALS__)return;window.__CBT_ADMIN_SIGNALS__=!0;
  function log(){try{console.log.apply(console,arguments)}catch(e){}}
  function warn(){try{console.warn.apply(console,arguments)}catch(e){}}
  function seenKey(b){return"CBT_BROADCAST_SEEN_"+(b.exam_id||"global")+"_"+(b.timestamp||b.id||"latest")}
  function targetMatches(b){
    const user=window.State&&window.State.user, kelas=String(b.kelas||"all").trim();
    if(!user)return!0;
    return !kelas||kelas==="all"||kelas===String(user.kelas||"").trim();
  }
  function statusMatches(b){
    const status=String(b.status||"all").trim().toUpperCase();
    return !status||status==="ALL"||status==="MENGERJAKAN"||status==="ONLINE"||status==="AKTIF";
  }
  function renderBroadcastMessage(message){
    const overlay=document.getElementById("broadcast-overlay"), modal=document.getElementById("broadcast-modal"), text=document.getElementById("broadcast-text");
    if(!overlay||!modal||!text)return;
    text.textContent=String(message);
    overlay.style.display="block";overlay.classList.add("active");overlay.style.opacity="1";
    modal.style.display="flex";modal.style.opacity="1";modal.style.transform="translate(-50%, -50%) scale(1)";
    if(navigator.vibrate)navigator.vibrate([100,50,100]);
  }
  function showBroadcast(b){
    if(!b||!b.message||!targetMatches(b)||!statusMatches(b))return;
    const ts=Number(b.timestamp||0);
    if(ts&&Date.now()-ts>10*60*1000)return;
    const key=seenKey(b);
    if(sessionStorage.getItem(key))return;
    sessionStorage.setItem(key,"1");
    renderBroadcastMessage(String(b.message));
  }
  function patchBroadcastModal(){
    if(window.closeBroadcastModal&&window.closeBroadcastModal.__cbtSignalsWrapped)return;
    const base=window.closeBroadcastModal;
    window.closeBroadcastModal=function(){
      if(typeof base==="function")base.apply(this,arguments);
      const overlay=document.getElementById("broadcast-overlay"), modal=document.getElementById("broadcast-modal");
      setTimeout(()=>{if(overlay){overlay.classList.remove("active");overlay.style.display="none";overlay.style.opacity="0"}if(modal)modal.style.display="none"},320);
    };
    window.closeBroadcastModal.__cbtSignalsWrapped=!0;
  }
  function startBroadcastPolling(){
    if(window.__CBT_BROADCAST_POLL__)return;
    const isExam=document.body&&document.body.classList.contains("exam-page");
    if(!isExam)return;
    window.__CBT_BROADCAST_POLL__=!0;
    const tick=async()=>{
      try{
        const st=window.State||{}, examId=st.config&&st.config.id_ujian;
        if(!st.examActive||!examId||typeof window.fetchSupabase!=="function")return;
        const res=await window.fetchSupabase("broadcasts",{exam_id:"eq."+examId,order:"timestamp.desc",limit:1});
        if(res.success&&res.data&&res.data.length)showBroadcast(res.data[0]);
      }catch(e){warn("[Broadcast] poll failed:",e&&e.message||e)}
    };
    setTimeout(tick,5000+Math.random()*10000);
    setInterval(tick,60000+Math.floor(Math.random()*30000));
  }
  async function openRemedial(examId,userId){
    const adminPass=sessionStorage.getItem("admin_pwd")||"";
    if(typeof window.invokeSupabaseFunction==="function"){
      const res=await window.invokeSupabaseFunction("admin_remedial",{adminPass,examId,userId},12000);
      if(res.success&&res.data&&res.data.success)return res.data;
      warn("[Remedial] Edge Function fallback:",res.error||res.status||"unknown");
    }
    if(typeof window.deleteSupabase==="function"){
      const id=String(examId)+"_"+String(userId);
      await window.deleteSupabase("hasil",{id:"eq."+id});
      await window.deleteSupabase("hasil",{exam_id:"eq."+examId,user_id:"eq."+userId});
      await window.deleteSupabase("online_status",{exam_id:"eq."+examId,user_id:"eq."+userId});
      await window.deleteSupabase("status_sync",{exam_id:"eq."+examId,user_id:"eq."+userId});
      await window.deleteSupabase("sync_answers",{exam_id:"eq."+examId,user_id:"eq."+userId});
      await window.deleteSupabase("reset_flags",{exam_id:"eq."+examId,user_id:"eq."+userId});
      const flag=await window.insertSupabase("reset_flags",{exam_id:String(examId),user_id:String(userId),time:Date.now()});
      if(flag&&flag.success)return{success:!0,examId,userId};
    }
    if(window.db&&typeof window.db.ref==="function"){
      await window.db.ref("/hasil/"+examId+"_"+userId).remove();
      await window.db.ref("/hasil/"+examId+"/"+userId).remove();
      await window.db.ref("/online_status/"+examId+"/"+userId).remove();
      await window.db.ref("/status_sync/"+examId+"/"+userId).remove();
      await window.db.ref("/reset_flags/"+examId+"/"+userId).set({time:Date.now()});
      return{success:!0,examId,userId};
    }
    throw new Error("Runtime remedial belum siap");
  }
  function patchAdminRemedialButtons(){
    if(window.deleteHasilRecord&&!window.deleteHasilRecord.__cbtSignalsWrapped){
      window.deleteHasilRecord=async function(examId,userId,nama){
        if(!examId||!userId)return window.showCustomAlert&&window.showCustomAlert("Gagal","Data hasil tidak valid.","❌");
        const label=nama?` milik ${nama}`:"";
        if(!confirm(`Hapus nilai${label} dan buka ujian ulang/remedial?`))return;
        window.showLoading&&window.showLoading("Membuka remedial...");
        try{
          await openRemedial(examId,userId);
          window.showCustomAlert&&window.showCustomAlert("Remedial Dibuka","Nilai dihapus, status pengerjaan dibersihkan, dan siswa bisa mulai ujian ulang setelah refresh/login ulang.","✅");
          if(typeof window.loadAdminHasil==="function")await window.loadAdminHasil(!0);
        }catch(e){
          window.showCustomAlert&&window.showCustomAlert("Gagal","Gagal membuka remedial: "+(e&&e.message||e),"❌");
        }finally{
          window.hideLoading&&window.hideLoading();
        }
      };
      window.deleteHasilRecord.__cbtSignalsWrapped=!0;
      log("[CBT Signals] deleteHasilRecord remedial patched");
    }
  }
  function esc(v){return String(v==null?"":v).replace(/[&<>"']/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;"}[c]))}
  async function fetchPesertaList(){
    if(window.adminState&&Array.isArray(window.adminState.peserta)&&window.adminState.peserta.length)return window.adminState.peserta;
    if(typeof window.fetchSupabase==="function"){
      const res=await window.fetchSupabase("peserta",{order:"kelas.asc,nama.asc"});
      if(res&&res.success&&Array.isArray(res.data)){
        const list=res.data.map(x=>({id:String(x.id||""),nama:x.nama||x.name||"",kelas:x.kelas||""}));
        window.adminState=window.adminState||{};window.adminState.peserta=list;
        return list;
      }
    }
    if(window.db&&typeof window.db.ref==="function"){
      const snap=await window.db.ref("/peserta").once("value"), data=snap.val()||{};
      return Object.keys(data).map(id=>({id,nama:data[id].nama||data[id].name||"",kelas:data[id].kelas||""}));
    }
    return[];
  }
  async function getPeserta(id){
    const list=await fetchPesertaList(), found=list.find(x=>String(x.id)===String(id));
    if(found)return found;
    if(typeof window.fetchSupabase==="function"){
      const res=await window.fetchSupabase("peserta",{id:"eq."+id,limit:1});
      if(res&&res.success&&res.data&&res.data.length)return{id:String(res.data[0].id||id),nama:res.data[0].nama||res.data[0].name||"",kelas:res.data[0].kelas||""};
    }
    if(window.db&&typeof window.db.ref==="function"){
      const snap=await window.db.ref("/peserta/"+id).once("value"), data=snap.val()||{};
      return{id:String(id),nama:data.nama||data.name||"",kelas:data.kelas||""};
    }
    return{id:String(id),nama:"",kelas:""};
  }
  async function fillClassControls(selected){
    const list=await fetchPesertaList(), classes=[...new Set(list.map(x=>String(x.kelas||"").trim()).filter(Boolean))].sort((a,b)=>a.localeCompare(b,"id-ID"));
    const data=document.getElementById("siswaKelasList");
    if(data)data.innerHTML=classes.map(k=>`<option value="${esc(k)}"></option>`).join("");
    const del=document.getElementById("filter-kelas-delete");
    if(del){
      const old=selected||del.value||"";
      del.innerHTML='<option value="">Semua Kelas</option>'+classes.map(k=>`<option value="${esc(k)}">${esc(k)}</option>`).join("");
      if(old&&classes.includes(old))del.value=old;
    }
    const print=document.getElementById("printKelas");
    if(print){
      const old=print.value||"";
      print.innerHTML='<option value="">Semua Kelas</option>'+classes.map(k=>`<option value="${esc(k)}">${esc(k)}</option>`).join("");
      if(old&&classes.includes(old))print.value=old;
    }
  }
  async function renderFilteredSiswaTable(){
    const tbody=document.getElementById("admin-siswa-tbody");
    if(!tbody)return;
    tbody.innerHTML='<tr><td colspan="4" class="text-center text-muted">Memuat...</td></tr>';
    try{
      const selected=(document.getElementById("filter-kelas-delete")?.value||"").trim();
      const list=await fetchPesertaList();
      const filtered=selected?list.filter(x=>String(x.kelas||"").trim()===selected):list;
      filtered.sort((a,b)=>String(a.kelas||"").localeCompare(String(b.kelas||""),"id-ID")||String(a.nama||"").localeCompare(String(b.nama||""),"id-ID"));
      tbody.innerHTML=filtered.length?filtered.map(s=>`<tr><td><strong>${esc(s.id)}</strong></td><td>${esc(s.nama)}</td><td>${esc(s.kelas)}</td><td><button class="btn btn-outline" onclick="editSiswa('${esc(String(s.id)).replace(/'/g,"&#39;")}')">📝</button> <button class="btn btn-outline" style="color:var(--danger)" onclick="deleteSiswa('${esc(String(s.id)).replace(/'/g,"&#39;")}')">🗑️</button></td></tr>`).join(""):`<tr><td colspan="4" class="text-center">${selected?`Tidak ada siswa di kelas ${esc(selected)}.`:"Belum ada data siswa."}</td></tr>`;
    }catch(e){
      warn("[SiswaFilter] render failed:",e&&e.message||e);
      tbody.innerHTML='<tr><td colspan="4" class="text-center text-muted">Gagal memuat siswa.</td></tr>';
    }
  }
  function patchClassFilter(){
    const sel=document.getElementById("filter-kelas-delete");
    if(!sel||sel.__cbtSignalsFilterPatched)return;
    const first=sel.querySelector("option[value='']");
    if(first)first.textContent="Semua Kelas";
    sel.addEventListener("change",()=>renderFilteredSiswaTable());
    sel.__cbtSignalsFilterPatched=!0;
  }
  function patchSiswaModal(){
    if(window.openSiswaModal&&window.openSiswaModal.__cbtSignalsWrapped)return;
    window.openSiswaModal=async function(id){
      const overlay=document.getElementById("siswa-overlay"), modal=document.getElementById("siswa-modal");
      if(!overlay||!modal)return;
      const title=document.getElementById("siswa-modal-title"), idInput=document.getElementById("siswaIdInput"), namaInput=document.getElementById("siswaNamaInput"), kelasInput=document.getElementById("siswaKelasInput");
      overlay.style.display="block";modal.style.display="flex";overlay.classList.add("active");
      setTimeout(()=>{overlay.style.opacity="1";modal.style.opacity="1";modal.style.transform="translate(-50%, -50%) scale(1)"},10);
      await fillClassControls();
      if(title)title.innerText=id?"Edit Siswa":"Tambah Siswa";
      if(idInput){idInput.value=id||"";idInput.readOnly=!!id}
      if(namaInput)namaInput.value="";
      if(kelasInput)kelasInput.value="";
      if(id){
        window.showLoading&&window.showLoading("Memuat data siswa...");
        try{
          const siswa=await getPeserta(id);
          if(namaInput)namaInput.value=siswa.nama||"";
          if(kelasInput)kelasInput.value=siswa.kelas||"";
          await fillClassControls(siswa.kelas||"");
        }catch(e){
          warn("[SiswaModal] load failed:",e&&e.message||e);
          window.showCustomAlert&&window.showCustomAlert("Gagal","Gagal memuat data siswa.","❌");
        }finally{window.hideLoading&&window.hideLoading()}
      }
    };
    window.openSiswaModal.__cbtSignalsWrapped=!0;
    window.editSiswa=function(id){window.openSiswaModal(id)};
    log("[CBT Signals] siswa modal patched");
  }
  function patchSiswaLoad(){
    if(typeof window.loadAdminSiswa!=="function"||window.loadAdminSiswa.__cbtSignalsClassPatch)return;
    window.loadAdminSiswa=async function(){
      await fillClassControls().catch(e=>warn("[SiswaClass] fill failed:",e&&e.message||e));
      patchClassFilter();
      await renderFilteredSiswaTable();
    };
    window.loadAdminSiswa.__cbtSignalsClassPatch=!0;
  }
  function wrapGasRun(){
    if(typeof window.gasRun!=="function"||window.gasRun.__cbtSignalsWrapped)return;
    const base=window.gasRun;
    async function wrapped(name,...args){
      if(name==="sendBroadcastAdmin"&&typeof window.invokeSupabaseFunction==="function"){
        const [examId,message,kelas,status]=args, adminPass=sessionStorage.getItem("admin_pwd")||"";
        const res=await window.invokeSupabaseFunction("admin_broadcast",{adminPass,examId,message,kelas:kelas||"all",status:status||"all"},12000);
        if(res.success&&res.data&&res.data.success)return res.data;
        warn("[Broadcast] Edge Function fallback:",res.error||res.status||"unknown");
      }
      if(name==="getAdminLaporanLengkap"&&typeof window.invokeSupabaseFunction==="function"){
        const adminPass=sessionStorage.getItem("admin_pwd")||"", examId=args[0]||"";
        const res=await window.invokeSupabaseFunction("admin_laporan",{adminPass,examId},15000);
        if(res.success&&res.data&&res.data.success)return res.data;
        warn("[AdminLaporan] Edge Function fallback:",res.error||res.status||"unknown");
      }
      if(name==="remedialStudent"||name==="resetStudentSession"){
        const [examId,userId]=args;
        if(examId&&userId)return await openRemedial(examId,userId);
      }
      const out=await base.apply(this,[name,...args]);
      if(name==="setStudentOnline"&&out&&out.broadcast)showBroadcast(out.broadcast);
      return out;
    }
    wrapped.__cbtSignalsWrapped=!0;window.gasRun=wrapped;log("[CBT Signals] gasRun wrapped");
  }
  function wrapInsert(){
    if(typeof window.insertSupabase!=="function"||window.insertSupabase.__cbtSignalsWrapped)return;
    const base=window.insertSupabase;
    async function wrapped(table,payload){
      if(table==="pelanggaran"&&typeof window.invokeSupabaseFunction==="function"){
        const res=await window.invokeSupabaseFunction("log_violation",payload,8000);
        if(res.success&&res.data&&res.data.success)return{success:!0,data:res.data};
        warn("[Violation] Edge Function fallback:",res.error||res.status||"unknown");
      }
      return base.apply(this,arguments);
    }
    wrapped.__cbtSignalsWrapped=!0;window.insertSupabase=wrapped;log("[CBT Signals] insertSupabase wrapped");
  }
  function boot(){wrapGasRun();wrapInsert();patchBroadcastModal();patchAdminRemedialButtons();patchSiswaModal();patchSiswaLoad();patchClassFilter();fillClassControls().catch(()=>{});startBroadcastPolling()}
  boot();
  window.addEventListener("supabase-patch-ready",boot);
  window.addEventListener("load",boot);
}();
